-- Recetas
INSERT INTO recetas (id, nombre, categoria, tiempo_preparacion, favorita, imagen, precio_por_porcion, porciones, category_id, ingredientes, pasos, consejos) VALUES

('a1b2c3d4-0001-4000-8000-000000000001',
 'Paella valenciana', 'espanola', 60, false,
 'https://images.unsplash.com/photo-1534080564583-6be75777b70a?w=800&q=80&crop=entropy',
 3.50, 4, '11111111-1111-1111-1111-111111111111',
 '[{"nombre":"arroz bomba","cantidad":400,"unidad":"g","familia":"cereales"},{"nombre":"pollo","cantidad":500,"unidad":"g","familia":"carnes"},{"nombre":"conejo","cantidad":400,"unidad":"g","familia":"carnes"},{"nombre":"judía verde plana","cantidad":200,"unidad":"g","familia":"verduras"},{"nombre":"garrofón","cantidad":100,"unidad":"g","familia":"legumbres"},{"nombre":"tomate triturado","cantidad":150,"unidad":"g","familia":"verduras"},{"nombre":"pimentón dulce","cantidad":1,"unidad":"cdta","familia":"especias"},{"nombre":"azafrán","cantidad":1,"unidad":"pizca","familia":"especias"},{"nombre":"caldo de pollo","cantidad":1200,"unidad":"ml","familia":"caldos"},{"nombre":"aceite de oliva","cantidad":60,"unidad":"ml","familia":"aceites"}]',
 '["Pon la paellera al fuego con el aceite a fuego medio-alto. Cuando esté caliente, añade el pollo y el conejo troceados, sálalos y dóralos por todos los lados durante 8-10 minutos hasta que tengan buen color.","Aparta la carne hacia los bordes. Añade la judía verde y el garrofón y sofríelos 5 minutos removiendo de vez en cuando.","Baja a fuego medio. Incorpora el tomate triturado y el pimentón dulce y remueve sin parar 1 minuto: el pimentón se quema en segundos, no lo dejes solo.","Vierte el caldo de pollo bien caliente y añade el azafrán. Sube a fuego fuerte, lleva a ebullición y prueba de sal.","Reparte el arroz por toda la paellera formando una cruz y luego nivélalo. A partir de aquí no vuelvas a removerlo.","Cocina a fuego fuerte 8 minutos y después a fuego bajo 10 minutos más, hasta que el arroz absorba casi todo el caldo y asome en la superficie.","Apaga el fuego, cubre la paella con un paño limpio y deja reposar 5 minutos antes de servir."]',
 '["El arroz bomba absorbe unas 3 veces su volumen en caldo; no lo enjuagues antes para que conserve el almidón que da untuosidad al plato.","Añade siempre el caldo caliente: si lo echas frío cortas la cocción y el arroz queda duro por dentro.","Cuando repartas el arroz no vuelvas a removerlo; si quieres socarrat, sube el fuego 30 segundos al final hasta oír que crepita, sin que llegue a oler a quemado."]'),

('a1b2c3d4-0002-4000-8000-000000000002',
 'Ramen de pollo', 'japonesa', 50, false,
 'https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=800&q=80&crop=entropy',
 4.00, 2, '44444444-4444-4444-4444-444444444444',
 '[{"nombre":"fideos ramen","cantidad":200,"unidad":"g","familia":"cereales"},{"nombre":"caldo de pollo","cantidad":1000,"unidad":"ml","familia":"caldos"},{"nombre":"pechuga de pollo","cantidad":300,"unidad":"g","familia":"carnes"},{"nombre":"salsa de soja","cantidad":40,"unidad":"ml","familia":"salsas"},{"nombre":"miso blanco","cantidad":2,"unidad":"cda","familia":"salsas"},{"nombre":"huevo","cantidad":2,"unidad":"ud","familia":"huevos"},{"nombre":"cebolleta","cantidad":2,"unidad":"ud","familia":"verduras"},{"nombre":"alga nori","cantidad":2,"unidad":"hoja","familia":"otros"},{"nombre":"maíz dulce","cantidad":100,"unidad":"g","familia":"verduras"},{"nombre":"jengibre fresco","cantidad":20,"unidad":"g","familia":"especias"}]',
 '["Saca los huevos de la nevera un rato antes para que estén a temperatura ambiente. Lleva un cazo con agua a ebullición, introdúcelos y cuécelos exactamente 7 minutos para que la yema quede cremosa. Pásalos a agua fría, pélalos y resérvalos.","Calienta el caldo de pollo a fuego medio. Añade el jengibre rallado, la salsa de soja y el miso y remueve hasta que el miso se disuelva del todo.","Baja a fuego suave e introduce la pechuga entera. Cuécela 15 minutos sin que el caldo llegue a hervir. Sácala y desmenúzala con dos tenedores.","Cuece los fideos ramen en agua hirviendo el tiempo que indique el paquete y escúrrelos.","Reparte los fideos en dos boles y cúbrelos con el caldo caliente. Coloca encima el pollo desmenuzado, el huevo partido por la mitad, el maíz, la cebolleta picada y el alga nori."]',
 '["Saca los huevos de la nevera antes de cocerlos: fríos, 7 minutos no bastan para lograr la yema cremosa.","No dejes que el caldo con miso llegue a hervir o perderá aroma y se volverá áspero.","Desmenuza el pollo cuando esté templado, no ardiendo, para no quemarte y que absorba mejor el caldo."]'),

('a1b2c3d4-0003-4000-8000-000000000003',
 'Gyozas de cerdo y col', 'japonesa', 45, false,
 'https://images.unsplash.com/photo-1496116218417-1a781b1c416c?w=800&q=80&crop=entropy',
 2.50, 4, '44444444-4444-4444-4444-444444444444',
 '[{"nombre":"obleas de gyoza","cantidad":24,"unidad":"ud","familia":"cereales"},{"nombre":"carne picada de cerdo","cantidad":300,"unidad":"g","familia":"carnes"},{"nombre":"col china","cantidad":200,"unidad":"g","familia":"verduras"},{"nombre":"cebolleta","cantidad":2,"unidad":"ud","familia":"verduras"},{"nombre":"jengibre fresco","cantidad":15,"unidad":"g","familia":"especias"},{"nombre":"salsa de soja","cantidad":20,"unidad":"ml","familia":"salsas"},{"nombre":"aceite de sésamo","cantidad":10,"unidad":"ml","familia":"aceites"}]',
 '["Pica la col china muy fina, ponla en un bol, sálala y déjala reposar 10 minutos. Después escúrrela apretándola con las manos para quitarle toda el agua.","En un bol, mezcla la carne de cerdo con la col, la cebolleta picada, el jengibre rallado, la salsa de soja y el aceite de sésamo hasta obtener un relleno homogéneo.","Pon una cucharadita de relleno en el centro de cada oblea. Moja el borde con agua, dóblala por la mitad y ciérrala haciendo pequeños pliegues para sellarla bien.","Calienta un poco de aceite en una sartén antiadherente a fuego medio-alto. Coloca las gyozas con la base plana hacia abajo y dóralas 2 minutos sin moverlas.","Añade 60 ml de agua de golpe, tapa enseguida y cocina al vapor 5 minutos.","Destapa y deja que se evapore el agua restante hasta que la base vuelva a quedar crujiente.","Sírvelas calientes con salsa de soja mezclada con un poco de vinagre de arroz."]',
 '["Salar y escurrir bien la col es clave: si suelta agua, el relleno moja la oblea y se rompe al cerrar.","Trabaja con las obleas tapadas con un paño húmedo; se secan y se agrietan en pocos minutos.","Mantén la carne de cerdo bien fría al mezclarla; así el relleno queda jugoso y es más fácil de manejar."]'),

('a1b2c3d4-0004-4000-8000-000000000004',
 'Pad Thai de gambas', 'tailandesa', 25, false,
 'https://images.unsplash.com/photo-1559314809-0d155014e29e?w=800&q=80&crop=entropy',
 5.00, 2, '55555555-5555-5555-5555-555555555555',
 '[{"nombre":"fideos de arroz planos","cantidad":200,"unidad":"g","familia":"cereales"},{"nombre":"gambas peladas","cantidad":250,"unidad":"g","familia":"pescados"},{"nombre":"huevo","cantidad":2,"unidad":"ud","familia":"huevos"},{"nombre":"brotes de soja","cantidad":150,"unidad":"g","familia":"verduras"},{"nombre":"cebolleta","cantidad":3,"unidad":"ud","familia":"verduras"},{"nombre":"salsa de tamarindo","cantidad":40,"unidad":"ml","familia":"salsas"},{"nombre":"salsa de pescado","cantidad":30,"unidad":"ml","familia":"salsas"},{"nombre":"azúcar de palma","cantidad":20,"unidad":"g","familia":"dulces"},{"nombre":"cacahuetes tostados","cantidad":50,"unidad":"g","familia":"frutos secos"},{"nombre":"lima","cantidad":1,"unidad":"ud","familia":"frutas"}]',
 '["Pon los fideos de arroz en un bol con agua fría y déjalos en remojo 30 minutos, hasta que estén flexibles pero aún firmes. Escúrrelos.","Mezcla en un vaso la salsa de tamarindo, la salsa de pescado y el azúcar de palma hasta que el azúcar se disuelva. Esta será la salsa del plato.","Calienta el wok a fuego muy fuerte con un poco de aceite. Saltea las gambas 1-2 minutos hasta que estén rosadas y retíralas.","En el mismo wok echa los huevos, deja que empiecen a cuajar y rómpelos en trozos con la espátula.","Añade los fideos escurridos y la salsa. Saltea 2 minutos removiendo, hasta que los fideos estén tiernos y hayan absorbido la salsa.","Devuelve las gambas al wok, añade los brotes de soja y la cebolleta y saltea 1 minuto más.","Sirve enseguida con los cacahuetes picados por encima y unos gajos de lima para exprimir al gusto."]',
 '["No dejes los fideos de arroz en remojo de más: si se ablandan del todo, se apelmazan al saltear.","Ten todos los ingredientes cortados y la salsa lista antes de encender el wok; el salteado dura apenas 5 minutos y no da tiempo a improvisar.","Las gambas frescas deben oler a mar; si huelen a amoníaco están pasadas, deséchalas."]'),

('a1b2c3d4-0005-4000-8000-000000000005',
 'Sopa de miso con tofu', 'japonesa', 15, false,
 'https://images.unsplash.com/photo-1744116927815-a04ba6629cf3?w=800&q=80&crop=entropy',
 2.00, 2, '44444444-4444-4444-4444-444444444444',
 '[{"nombre":"pasta de miso blanco","cantidad":3,"unidad":"cda","familia":"salsas"},{"nombre":"tofu sedoso","cantidad":200,"unidad":"g","familia":"proteinas"},{"nombre":"alga wakame seca","cantidad":10,"unidad":"g","familia":"otros"},{"nombre":"caldo dashi","cantidad":800,"unidad":"ml","familia":"caldos"},{"nombre":"cebolleta","cantidad":2,"unidad":"ud","familia":"verduras"},{"nombre":"salsa de soja","cantidad":10,"unidad":"ml","familia":"salsas"}]',
 '["Pon el alga wakame en un bol con agua fría y déjala 5 minutos para que se hidrate. Escúrrela.","Calienta el caldo dashi en una olla a fuego suave, sin dejar que llegue a hervir.","Pon el miso en un cuenco, añade un cucharón de caldo caliente y remueve hasta disolverlo. Viértelo de nuevo en la olla.","Incorpora el tofu cortado en dados pequeños y el wakame escurrido.","Mantén a fuego suave 2 minutos sin dejar que hierva: si hierve, el miso pierde sabor y propiedades.","Reparte en dos boles, añade la salsa de soja al gusto y termina con la cebolleta picada por encima."]',
 '["El miso es un fermento vivo: añádelo al final y sin hervir para conservar su sabor y sus probióticos.","Disuélvelo siempre aparte con un poco de caldo; echado directo en bloque queda con grumos.","El tofu sedoso es muy frágil; córtalo con cuidado e incorpóralo casi al servir para que no se deshaga."]'),

('a1b2c3d4-0006-4000-8000-000000000006',
 'Risotto de setas', 'italiana', 40, false,
 'https://images.unsplash.com/photo-1476124369491-e7addf5db371?w=800&q=80&crop=entropy',
 4.50, 4, '44444444-4444-4444-4444-444444444444',
 '[{"nombre":"arroz arborio","cantidad":320,"unidad":"g","familia":"cereales"},{"nombre":"setas variadas","cantidad":400,"unidad":"g","familia":"verduras"},{"nombre":"cebolla","cantidad":1,"unidad":"ud","familia":"verduras"},{"nombre":"ajo","cantidad":2,"unidad":"dientes","familia":"verduras"},{"nombre":"vino blanco seco","cantidad":120,"unidad":"ml","familia":"bebidas"},{"nombre":"caldo de verduras","cantidad":1200,"unidad":"ml","familia":"caldos"},{"nombre":"parmesano rallado","cantidad":80,"unidad":"g","familia":"lacteos"},{"nombre":"mantequilla","cantidad":40,"unidad":"g","familia":"lacteos"},{"nombre":"aceite de oliva","cantidad":30,"unidad":"ml","familia":"aceites"}]',
 '["Calienta el caldo de verduras en un cazo aparte y mantenlo caliente a fuego mínimo durante toda la receta.","En una cazuela ancha, sofríe la cebolla y el ajo picados en el aceite a fuego suave 5 minutos, hasta que estén transparentes pero sin dorarse.","Sube a fuego fuerte, añade las setas y saltéalas hasta que suelten el agua y esta se evapore, unos 5 minutos.","Incorpora el arroz arborio y remuévelo 2 minutos para que se tueste ligeramente.","Vierte el vino blanco y remueve hasta que se absorba por completo.","Añade el caldo caliente cazo a cazo, removiendo a menudo y esperando a que se absorba antes de añadir el siguiente. Repite unos 18 minutos, hasta que el arroz quede cremoso y al dente (tierno pero con un puntito firme en el centro del grano).","Retira del fuego, añade la mantequilla y el parmesano y remueve con energía hasta que quede cremoso. Sirve inmediatamente."]',
 '["Usa arroz arborio o carnaroli; los de grano largo no sueltan el almidón que da cremosidad y no valen aquí.","No laves el arroz: ese almidón es justo lo que liga el risotto.","Mantén el caldo caliente al lado; si lo añades frío, frenas la cocción y el grano queda duro por fuera."]'),

('a1b2c3d4-0007-4000-8000-000000000007',
 'Tiramisú', 'italiana', 30, false,
 'https://images.unsplash.com/photo-1571877227200-a0d98ea607e9?w=800&q=80&crop=entropy',
 3.00, 6, '33333333-3333-3333-3333-333333333333',
 '[{"nombre":"mascarpone","cantidad":500,"unidad":"g","familia":"lacteos"},{"nombre":"huevos","cantidad":4,"unidad":"ud","familia":"huevos"},{"nombre":"azúcar","cantidad":100,"unidad":"g","familia":"dulces"},{"nombre":"bizcochos savoiardi","cantidad":24,"unidad":"ud","familia":"cereales"},{"nombre":"café expreso","cantidad":300,"unidad":"ml","familia":"bebidas"},{"nombre":"cacao en polvo","cantidad":30,"unidad":"g","familia":"dulces"},{"nombre":"amaretto","cantidad":30,"unidad":"ml","familia":"bebidas"}]',
 '["Prepara el café expreso, mézclalo con el amaretto y déjalo enfriar en un plato hondo.","Separa las yemas de las claras. Bate las yemas con el azúcar 3-4 minutos hasta que la mezcla blanquee y quede espumosa.","Añade el mascarpone a las yemas y mézclalo con movimientos suaves de abajo arriba hasta obtener una crema lisa.","Bate las claras hasta el punto de nieve: quedan firmes y no se caen si giras el bol. Incorpóralas a la crema con movimientos envolventes para que no se bajen.","Moja los bizcochos en el café un segundo por cada lado, sin empaparlos, y cubre con ellos la base del molde.","Extiende la mitad de la crema, pon otra capa de bizcochos mojados y termina con el resto de la crema, alisando la superficie.","Refrigera un mínimo de 4 horas. Justo antes de servir, espolvorea el cacao por encima con ayuda de un colador."]',
 '["Lleva huevo crudo: usa huevos muy frescos o pasteurizados y mantén el postre siempre refrigerado, sobre todo si lo van a comer embarazadas, niños o personas mayores.","No empapes los bizcochos; un segundo por cada lado basta o quedarán aguados.","Saca el mascarpone de la nevera justo antes de usarlo y no lo batas en exceso, o se corta y se vuelve granuloso."]'),

('a1b2c3d4-0008-4000-8000-000000000008',
 'Fabada asturiana', 'espanola', 120, false,
 'https://images.unsplash.com/photo-1512003867696-6d5ce6835040?w=800&q=80&crop=entropy',
 3.80, 6, '11111111-1111-1111-1111-111111111111',
 '[{"nombre":"fabes asturianas","cantidad":500,"unidad":"g","familia":"legumbres"},{"nombre":"chorizo asturiano","cantidad":200,"unidad":"g","familia":"carnes"},{"nombre":"morcilla asturiana","cantidad":200,"unidad":"g","familia":"carnes"},{"nombre":"lacón","cantidad":200,"unidad":"g","familia":"carnes"},{"nombre":"panceta curada","cantidad":150,"unidad":"g","familia":"carnes"},{"nombre":"azafrán","cantidad":1,"unidad":"pizca","familia":"especias"},{"nombre":"pimentón","cantidad":1,"unidad":"cdta","familia":"especias"}]',
 '["La noche anterior, pon las fabes en un bol grande cubiertas con abundante agua fría y déjalas en remojo.","Escurre las fabes y ponlas en una olla. Cúbrelas con agua fría (3-4 dedos por encima), añade el chorizo, la morcilla, el lacón y la panceta y lleva a ebullición a fuego fuerte.","Retira con una espumadera la espuma que suba a la superficie. Baja a fuego muy suave y cuece destapado, muy lento, 2 horas. Cada vez que el agua baje del nivel de las fabes, añade un chorro de agua fría.","A mitad de la cocción, disuelve el azafrán y el pimentón en un poco de caldo caliente y añádelo a la olla.","Prueba el caldo al final y ajusta de sal solo si hace falta, ya que los embutidos sueltan bastante.","Saca las carnes, córtalas en rodajas y sírvelas junto a las fabes, mejor en cazuela de barro."]',
 '["Remoja las fabes un mínimo de 8 horas; sin remojo quedan duras y se despellejan al cocer.","No las remuevas con cuchara: mueve la olla con un vaivén suave para que no se rompan.","No añadas sal al principio; los embutidos sueltan bastante y es fácil pasarse."]'),

('a1b2c3d4-0009-4000-8000-000000000009',
 'Croquetas de jamón', 'espanola', 90, false,
 'https://images.unsplash.com/photo-1751199393315-fbcae4eabd4c?w=800&q=80&crop=entropy',
 2.20, 4, '11111111-1111-1111-1111-111111111111',
 '[{"nombre":"jamón serrano","cantidad":150,"unidad":"g","familia":"carnes"},{"nombre":"harina","cantidad":100,"unidad":"g","familia":"cereales"},{"nombre":"mantequilla","cantidad":80,"unidad":"g","familia":"lacteos"},{"nombre":"leche entera","cantidad":700,"unidad":"ml","familia":"lacteos"},{"nombre":"nuez moscada","cantidad":1,"unidad":"pizca","familia":"especias"},{"nombre":"huevo","cantidad":2,"unidad":"ud","familia":"huevos"},{"nombre":"pan rallado","cantidad":150,"unidad":"g","familia":"cereales"},{"nombre":"aceite de girasol","cantidad":500,"unidad":"ml","familia":"aceites"}]',
 '["Derrite la mantequilla en una sartén a fuego medio y sofríe el jamón serrano picado muy fino durante 2 minutos.","Añade la harina de golpe y cocínala 3 minutos removiendo sin parar, hasta que tome color dorado claro y pierda el sabor a crudo.","Vierte la leche caliente poco a poco sin dejar de remover, mejor con varillas, hasta obtener una masa espesa y sin grumos (bechamel).","Sazona con sal y nuez moscada. Vierte la masa en una fuente, cúbrela tocando la superficie con film y enfríala en la nevera al menos 2 horas.","Con las manos, forma las croquetas. Pásalas primero por huevo batido y luego por pan rallado, cubriéndolas bien.","Calienta abundante aceite de girasol a fuego medio-alto. Estará a punto (unos 180 °C) cuando al echar un trocito de pan burbujee al momento sin quemarse. Fríe las croquetas por tandas hasta que estén doradas y escúrrelas sobre papel de cocina."]',
 '["Cocina bien la harina antes de añadir la leche, o la bechamel sabrá a crudo.","Cubre la masa tocando la superficie con film antes de enfriarla, así no forma costra.","Comprueba el aceite con un trocito de pan: si burbujea al momento sin humear, está en su punto (unos 180 °C)."]'),

('a1b2c3d4-0010-4000-8000-000000000010',
 'Ensalada griega', 'griega', 10, false,
 'https://images.unsplash.com/photo-1540189549336-e6e99c3679fe?w=800&q=80&crop=entropy',
 2.50, 2, '55555555-5555-5555-5555-555555555555',
 '[{"nombre":"tomate","cantidad":3,"unidad":"ud","familia":"verduras"},{"nombre":"pepino","cantidad":1,"unidad":"ud","familia":"verduras"},{"nombre":"cebolla roja","cantidad":1,"unidad":"ud","familia":"verduras"},{"nombre":"queso feta","cantidad":200,"unidad":"g","familia":"lacteos"},{"nombre":"aceitunas kalamata","cantidad":100,"unidad":"g","familia":"otros"},{"nombre":"pimiento verde","cantidad":1,"unidad":"ud","familia":"verduras"},{"nombre":"aceite de oliva virgen extra","cantidad":50,"unidad":"ml","familia":"aceites"},{"nombre":"orégano seco","cantidad":1,"unidad":"cdta","familia":"especias"},{"nombre":"vinagre de vino tinto","cantidad":20,"unidad":"ml","familia":"acidos"}]',
 '["Lava las verduras. Corta los tomates en gajos gruesos y el pepino en medias lunas de medio centímetro.","Corta la cebolla roja en aros finos y el pimiento verde en tiras.","Pon todas las verduras en una fuente. Reparte las aceitunas kalamata y coloca el queso feta en un bloque entero encima.","Aliña con el aceite de oliva, el vinagre de vino tinto, el orégano seco y una pizca de sal.","Sirve enseguida, sin remover demasiado para que el bloque de feta se mantenga entero."]',
 '["No desmenuces el feta: en bloque se mantiene cremoso y no se deshace con el aliño.","Sala justo antes de servir; si lo haces antes, el tomate y el pepino sueltan agua y aguan la ensalada.","Al llevar tan pocos ingredientes, usa tomate bien maduro y aceite de oliva virgen extra: aquí se nota su calidad."]'),

('a1b2c3d4-0011-4000-8000-000000000011',
 'Hamburguesa smash', 'americana', 20, false,
 'https://images.unsplash.com/photo-1568901346375-23c9450c58cd?w=800&q=80&crop=entropy',
 5.50, 2, '11111111-1111-1111-1111-111111111111',
 '[{"nombre":"carne picada de ternera 80/20","cantidad":400,"unidad":"g","familia":"carnes"},{"nombre":"panecillos brioche","cantidad":2,"unidad":"ud","familia":"cereales"},{"nombre":"queso cheddar","cantidad":4,"unidad":"lonchas","familia":"lacteos"},{"nombre":"cebolla","cantidad":1,"unidad":"ud","familia":"verduras"},{"nombre":"lechuga","cantidad":4,"unidad":"hojas","familia":"verduras"},{"nombre":"tomate","cantidad":1,"unidad":"ud","familia":"verduras"},{"nombre":"mayonesa","cantidad":2,"unidad":"cda","familia":"salsas"},{"nombre":"mostaza americana","cantidad":1,"unidad":"cda","familia":"salsas"},{"nombre":"sal y pimienta","cantidad":1,"unidad":"al gusto","familia":"especias"}]',
 '["Divide la carne en 4 bolas de unos 100 g sin apretarlas, solo dándoles forma redonda.","Calienta una plancha o sartén de hierro a fuego muy fuerte hasta que empiece a humear.","Pon una bola sobre la plancha y aplástala con una espátula ancha y firme durante 10 segundos, hasta dejarla muy fina.","Salpimienta la cara de arriba y cocina 2 minutos sin moverla, hasta que los bordes queden crujientes.","Dale la vuelta, pon encima una loncha de queso cheddar y deja que se funda 1 minuto.","Tuesta los panecillos brioche en la misma plancha. Unta la base con mayonesa y mostaza y monta con la lechuga, el tomate, la cebolla y dos hamburguesas por pan."]',
 '["Cuanto menos manosees y aprietes la bola de carne, más jugosa quedará la hamburguesa.","La plancha debe humear antes de aplastar la carne: así se forma la costra dorada y sabrosa.","Salpimienta después de aplastar, nunca al formar la bola, o la carne suelta agua y no se dora."]'),

('a1b2c3d4-0012-4000-8000-000000000012',
 'Brownies de chocolate', 'americana', 40, false,
 'https://images.unsplash.com/photo-1624353365286-3f8d62daad51?w=800&q=80&crop=entropy',
 1.50, 9, '33333333-3333-3333-3333-333333333333',
 '[{"nombre":"chocolate negro 70%","cantidad":200,"unidad":"g","familia":"dulces"},{"nombre":"mantequilla","cantidad":120,"unidad":"g","familia":"lacteos"},{"nombre":"huevos","cantidad":3,"unidad":"ud","familia":"huevos"},{"nombre":"azúcar","cantidad":200,"unidad":"g","familia":"dulces"},{"nombre":"harina","cantidad":80,"unidad":"g","familia":"cereales"},{"nombre":"cacao en polvo","cantidad":30,"unidad":"g","familia":"dulces"},{"nombre":"nueces","cantidad":100,"unidad":"g","familia":"frutos secos"},{"nombre":"sal","cantidad":1,"unidad":"pizca","familia":"especias"}]',
 '["Precalienta el horno a 175 °C con calor arriba y abajo. Forra un molde cuadrado de 20 cm con papel de horno.","Trocea el chocolate y ponlo con la mantequilla en un bol. Fúndelo al baño María (el bol sobre un cazo con agua caliente, sin que el agua toque el bol) y deja que se temple.","Bate los huevos con el azúcar 3-4 minutos, hasta que la mezcla blanquee y doble su volumen.","Añade el chocolate fundido y templado a los huevos y mézclalo con movimientos suaves envolventes.","Tamiza por encima la harina, el cacao y la sal. Intégralo justo hasta que no queden restos secos, sin batir de más.","Añade las nueces troceadas, vierte la masa en el molde y hornea 25 minutos. Estará listo cuando la superficie esté cuajada pero el centro tiemble un poco: acaba de asentarse al enfriar."]',
 '["Funde el chocolate al baño María suave; si se recalienta se corta y queda granuloso.","No batas la masa después de añadir la harina: el exceso de movimiento la vuelve dura en lugar de jugosa.","Sácalo del horno con el centro aún tembloroso; termina de cuajar al enfriar y así queda húmedo por dentro."]'),

('a1b2c3d4-0013-4000-8000-000000000013',
 'Macarons de frambuesa', 'francesa', 60, false,
 'https://images.unsplash.com/photo-1470124182917-cc6e71b22ecc?w=800&q=80&crop=entropy',
 2.00, 12, '22222222-2222-2222-2222-222222222222',
 '[{"nombre":"almendra molida tamizada","cantidad":125,"unidad":"g","familia":"frutos secos"},{"nombre":"azúcar glas tamizado","cantidad":225,"unidad":"g","familia":"dulces"},{"nombre":"claras de huevo envejecidas","cantidad":100,"unidad":"g","familia":"huevos"},{"nombre":"azúcar","cantidad":75,"unidad":"g","familia":"dulces"},{"nombre":"colorante rojo","cantidad":2,"unidad":"gotas","familia":"otros"},{"nombre":"frambuesas","cantidad":150,"unidad":"g","familia":"frutas"},{"nombre":"nata para montar","cantidad":100,"unidad":"ml","familia":"lacteos"},{"nombre":"chocolate blanco","cantidad":100,"unidad":"g","familia":"dulces"}]',
 '["Mezcla la almendra molida con el azúcar glas y tamiza la mezcla dos veces para que quede muy fina.","Bate las claras envejecidas y, cuando espumen, añade el azúcar poco a poco hasta montarlas a punto de nieve firme y brillante.","Añade el colorante rojo e incorpora la mezcla de almendra. Haz el macaronage: aplasta y mezcla con la espátula hasta que la masa caiga formando una cinta continua que se reabsorbe en unos segundos.","Pon la masa en una manga y escudilla círculos de 3,5 cm sobre una bandeja con papel de horno. Golpea la bandeja contra la mesa y deja secar los macarons 30 minutos, hasta que al tocarlos no se peguen al dedo.","Hornea a 145 °C durante 14 minutos. Déjalos enfriar por completo antes de despegarlos del papel.","Prepara el ganache: calienta la nata, viértela sobre el chocolate blanco troceado y remueve hasta fundirlo. Deja enfriar y móntalo ligeramente con varillas.","Tritura las frambuesas, mézclalas con el ganache y rellena los macarons emparejándolos de dos en dos. Guárdalos 24 horas en la nevera antes de comerlos."]',
 '["Pesa cada ingrediente al gramo: en repostería fina un pequeño desajuste arruina la textura.","Las claras envejecidas (1-2 días en la nevera y luego a temperatura ambiente) montan más estables.","No te saltes el secado de las conchas: hornear antes de que dejen de pegarse al dedo impide que salga el pie."]'),

('a1b2c3d4-0014-4000-8000-000000000014',
 'Tarta de zanahoria', 'americana', 55, false,
 'https://images.unsplash.com/photo-1566121933407-3c7ccdd26763?w=800&q=80&crop=entropy',
 3.50, 8, '22222222-2222-2222-2222-222222222222',
 '[{"nombre":"zanahoria rallada","cantidad":300,"unidad":"g","familia":"verduras"},{"nombre":"harina","cantidad":250,"unidad":"g","familia":"cereales"},{"nombre":"azúcar moreno","cantidad":200,"unidad":"g","familia":"dulces"},{"nombre":"aceite de girasol","cantidad":180,"unidad":"ml","familia":"aceites"},{"nombre":"huevos","cantidad":3,"unidad":"ud","familia":"huevos"},{"nombre":"canela molida","cantidad":2,"unidad":"cdta","familia":"especias"},{"nombre":"nuez moscada","cantidad":0.5,"unidad":"cdta","familia":"especias"},{"nombre":"levadura","cantidad":1.5,"unidad":"cdta","familia":"cereales"},{"nombre":"queso crema","cantidad":300,"unidad":"g","familia":"lacteos"},{"nombre":"azúcar glas","cantidad":150,"unidad":"g","familia":"dulces"}]',
 '["Precalienta el horno a 180 °C. Engrasa dos moldes redondos de 20 cm.","Bate los huevos con el azúcar moreno y el aceite de girasol hasta obtener una mezcla homogénea.","Tamiza por encima la harina, la levadura, la canela y la nuez moscada e intégralo.","Añade la zanahoria rallada y mezcla hasta obtener una masa uniforme.","Reparte la masa entre los dos moldes y hornea 30-35 minutos. Estará lista cuando al pinchar el centro con un palillo salga limpio. Desmolda y deja enfriar por completo.","Prepara el frosting: bate el queso crema frío con el azúcar glas hasta obtener una crema suave y sin grumos.","Coloca un bizcocho, cúbrelo con frosting, pon el segundo encima y cubre toda la tarta. Consérvala en la nevera hasta servir."]',
 '["Ralla la zanahoria fina; rallada gruesa suelta agua y queda cruda dentro del bizcocho.","Usa el queso crema bien frío para el frosting; templado, la cobertura queda líquida.","Enfría del todo los bizcochos antes de cubrirlos o el frosting se derretirá."]'),

('a1b2c3d4-0015-4000-8000-000000000015',
 'Mousse de chocolate negro', 'francesa', 25, false,
 'https://images.unsplash.com/photo-1744988870979-43fcbfdd0804?w=800&q=80&crop=entropy',
 2.80, 4, '33333333-3333-3333-3333-333333333333',
 '[{"nombre":"chocolate negro 70%","cantidad":200,"unidad":"g","familia":"dulces"},{"nombre":"huevos","cantidad":4,"unidad":"ud","familia":"huevos"},{"nombre":"azúcar","cantidad":60,"unidad":"g","familia":"dulces"},{"nombre":"mantequilla","cantidad":30,"unidad":"g","familia":"lacteos"},{"nombre":"nata para montar","cantidad":200,"unidad":"ml","familia":"lacteos"},{"nombre":"sal","cantidad":1,"unidad":"pizca","familia":"especias"}]',
 '["Trocea el chocolate y fúndelo con la mantequilla al baño María. Deja que se temple.","Separa las yemas de las claras. Bate las yemas con la mitad del azúcar hasta que blanqueen e incorpóralas al chocolate templado.","Monta la nata con varillas hasta que esté firme y resérvala en la nevera.","Monta las claras con el resto del azúcar y una pizca de sal hasta punto de nieve firme.","Incorpora primero la nata al chocolate con movimientos envolventes y después las claras en tres tandas, con suavidad para que la mousse quede aireada.","Reparte en copas o vasos y refrigera un mínimo de 3 horas antes de servir."]',
 '["Lleva huevo crudo: usa huevos frescos o pasteurizados y consérvala siempre en frío, sobre todo si la van a comer embarazadas, niños o personas mayores.","Templa el chocolate antes de unir las yemas; si está caliente, las cuaja.","Integra las claras en varias tandas y con suavidad para no perder el aire que da la textura."]'),

('a1b2c3d4-0016-4000-8000-000000000016',
 'Leche frita', 'espanola', 40, false,
 'https://images.unsplash.com/photo-1551024506-0bccd828d307?w=800&q=80&crop=entropy',
 1.80, 6, '22222222-2222-2222-2222-222222222222',
 '[{"nombre":"leche entera","cantidad":600,"unidad":"ml","familia":"lacteos"},{"nombre":"harina","cantidad":80,"unidad":"g","familia":"cereales"},{"nombre":"maicena","cantidad":40,"unidad":"g","familia":"cereales"},{"nombre":"azúcar","cantidad":120,"unidad":"g","familia":"dulces"},{"nombre":"canela en rama","cantidad":1,"unidad":"ud","familia":"especias"},{"nombre":"piel de limón","cantidad":1,"unidad":"tira","familia":"frutas"},{"nombre":"huevo","cantidad":2,"unidad":"ud","familia":"huevos"},{"nombre":"aceite de girasol","cantidad":300,"unidad":"ml","familia":"aceites"},{"nombre":"canela molida y azúcar para rebozar","cantidad":50,"unidad":"g","familia":"dulces"}]',
 '["Reserva un vaso de la leche fría. Calienta el resto en un cazo con la canela en rama y la piel de limón hasta que hierva suavemente; retira del fuego, tapa y deja infusionar 10 minutos. Cuela.","En un bol, disuelve la harina, la maicena y el azúcar con el vaso de leche fría reservada, removiendo hasta que no queden grumos.","Vierte la leche infusionada caliente sobre la mezcla anterior y devuélvelo todo al cazo. Cuece a fuego suave removiendo sin parar hasta que espese mucho y se despegue de las paredes.","Vierte la masa en una fuente engrasada formando una capa de 2 cm. Alísala y refrigérala 3 horas hasta que esté firme.","Corta la masa en rectángulos, pásalos por huevo batido y fríelos en aceite caliente pero no humeante (una gota de masa debe burbujear al momento) hasta que estén dorados por ambos lados. Escúrrelos sobre papel de cocina.","Rebózalos en azúcar mezclado con canela molida y sírvelos calientes."]',
 '["Cuece la crema hasta que se despegue bien del cazo; si queda floja, no cuajará y se deshará al freír.","Déjala enfriar bien firme (unas 3 horas) antes de cortarla, o no aguantará el rebozado.","Fríe en aceite caliente pero no humeante: una gota de masa debe burbujear al momento sin quemarse."]'),

('a1b2c3d4-0017-4000-8000-000000000017',
 'Tacos de pollo al pastor', 'mexicana', 35, false,
 'https://images.unsplash.com/photo-1565299585323-38d6b0865b47?w=800&q=80&crop=entropy',
 4.00, 4, '11111111-1111-1111-1111-111111111111',
 '[{"nombre":"pechuga de pollo","cantidad":500,"unidad":"g","familia":"carnes"},{"nombre":"tortillas de maíz","cantidad":8,"unidad":"ud","familia":"cereales"},{"nombre":"chile guajillo seco","cantidad":3,"unidad":"ud","familia":"especias"},{"nombre":"piña en rodajas","cantidad":150,"unidad":"g","familia":"frutas"},{"nombre":"cebolla","cantidad":1,"unidad":"ud","familia":"verduras"},{"nombre":"cilantro fresco","cantidad":20,"unidad":"g","familia":"hierbas"},{"nombre":"ajo","cantidad":2,"unidad":"dientes","familia":"verduras"},{"nombre":"vinagre de manzana","cantidad":30,"unidad":"ml","familia":"acidos"},{"nombre":"achiote en pasta","cantidad":1,"unidad":"cda","familia":"especias"},{"nombre":"lima","cantidad":2,"unidad":"ud","familia":"frutas"}]',
 '["Pon los chiles guajillo en un bol con agua caliente y déjalos hidratar 20 minutos. Escúrrelos y tritúralos con el ajo, la pasta de achiote y el vinagre de manzana hasta obtener una salsa roja lisa.","Corta la pechuga en filetes finos, cúbrelos con la salsa roja y déjalos marinar en la nevera un mínimo de 2 horas, mejor toda la noche.","Asa el pollo en una plancha o parrilla a fuego fuerte hasta que esté bien dorado por fuera y hecho por dentro. Déjalo reposar 5 minutos y pícalo en trozos pequeños.","Calienta las tortillas de maíz en una sartén seca, unos segundos por cada lado, hasta que estén flexibles.","Asa las rodajas de piña en la misma plancha hasta que se doren y caramelicen. Pícalas.","Monta cada taco con el pollo, la piña, cebolla picada y cilantro. Sírvelos con gajos de lima para exprimir."]',
 '["Marina el pollo un mínimo de 2 horas, mejor de un día para otro: el achiote y el vinagre lo ablandan y le dan color.","Ásalo a fuego fuerte para dorarlo por fuera sin secarlo; déjalo reposar antes de picarlo para que no pierda los jugos.","Calienta las tortillas de maíz justo antes de montar; frías se rompen al doblarlas."]'),

('a1b2c3d4-0018-4000-8000-000000000018',
 'Sushi rolls de salmón', 'japonesa', 45, false,
 'https://images.unsplash.com/photo-1553621042-f6e147245754?w=800&q=80&crop=entropy',
 6.50, 2, '44444444-4444-4444-4444-444444444444',
 '[{"nombre":"arroz para sushi","cantidad":300,"unidad":"g","familia":"cereales"},{"nombre":"salmón fresco para sashimi","cantidad":200,"unidad":"g","familia":"pescados"},{"nombre":"hojas de nori","cantidad":4,"unidad":"ud","familia":"otros"},{"nombre":"vinagre de arroz","cantidad":50,"unidad":"ml","familia":"acidos"},{"nombre":"azúcar","cantidad":20,"unidad":"g","familia":"dulces"},{"nombre":"sal","cantidad":5,"unidad":"g","familia":"especias"},{"nombre":"aguacate","cantidad":1,"unidad":"ud","familia":"frutas"},{"nombre":"pepino","cantidad":0.5,"unidad":"ud","familia":"verduras"},{"nombre":"salsa de soja","cantidad":50,"unidad":"ml","familia":"salsas"},{"nombre":"wasabi","cantidad":1,"unidad":"cdta","familia":"especias"}]',
 '["Lava el arroz bajo el grifo, removiendo, hasta que el agua salga clara. Escúrrelo, ponlo en una olla con 330 ml de agua, tápalo y llévalo a ebullición; baja el fuego y cuece 12 minutos. Apaga y deja reposar tapado 10 minutos.","Mezcla el vinagre de arroz, el azúcar y la sal hasta que se disuelvan. Vierte sobre el arroz caliente y mézclalo con una espátula haciendo cortes, sin aplastarlo. Abanícalo para enfriarlo hasta temperatura ambiente.","Corta en tiras largas y finas el salmón (que debe haber estado congelado a −20 °C un mínimo de 24-48 h para eliminar el anisakis), el aguacate y el pepino.","Coloca una hoja de nori sobre una esterilla de bambú. Extiende una capa fina de arroz cubriéndola y dejando 2 cm libres en el borde superior.","Pon el relleno en una línea sobre el arroz y enrolla con firmeza ayudándote de la esterilla, apretando para que quede compacto.","Moja el cuchillo en agua y corta cada rollo en 8 piezas, limpiando la hoja entre cortes. Sirve con salsa de soja y wasabi."]',
 '["El salmón crudo debe congelarse a -20 °C un mínimo de 24-48 horas, o comprarse ya ultracongelado, para eliminar el anisakis. Nunca lo uses fresco sin haberlo congelado.","Manipula el pescado bien frío, con tabla y cuchillo limpios reservados solo para él.","No aprietes el arroz al extenderlo sobre el nori; debe quedar suelto o el bocado resultará apelmazado."]'),

('a1b2c3d4-0019-4000-8000-000000000019',
 'Pizza margherita', 'italiana', 90, false,
 'https://images.unsplash.com/photo-1574071318508-1cdbab80d002?w=800&q=80&crop=entropy',
 3.20, 4, '11111111-1111-1111-1111-111111111111',
 '[{"nombre":"harina de fuerza W300","cantidad":500,"unidad":"g","familia":"cereales"},{"nombre":"agua tibia","cantidad":325,"unidad":"ml","familia":"otros"},{"nombre":"levadura seca","cantidad":3,"unidad":"g","familia":"cereales"},{"nombre":"sal","cantidad":10,"unidad":"g","familia":"especias"},{"nombre":"tomates san marzano","cantidad":400,"unidad":"g","familia":"verduras"},{"nombre":"mozzarella fior di latte","cantidad":300,"unidad":"g","familia":"lacteos"},{"nombre":"hojas de albahaca fresca","cantidad":10,"unidad":"ud","familia":"hierbas"},{"nombre":"aceite de oliva virgen extra","cantidad":30,"unidad":"ml","familia":"aceites"}]',
 '["Disuelve la levadura seca en el agua tibia. Añade la harina y la sal y mezcla hasta formar una masa; amásala 10 minutos hasta que quede lisa y elástica.","Pon la masa en un bol ligeramente aceitado, tápala y déjala fermentar 24 horas en la nevera.","Saca la masa de la nevera 2 horas antes de usarla. Divídela en dos bolas y déjalas reposar tapadas a temperatura ambiente.","Precalienta el horno al máximo (250 °C o más) con una bandeja o piedra dentro durante 30 minutos.","Aplasta los tomates san marzano con las manos y una pizca de sal. Estira cada bola de masa con las manos, desde el centro hacia fuera, dejando el borde más grueso.","Reparte la salsa de tomate sobre la masa y añade la mozzarella escurrida en trozos. Hornea sobre la bandeja caliente 8-10 minutos, hasta que el borde esté dorado.","Nada más sacarla, coloca las hojas de albahaca fresca y riega con un hilo de aceite de oliva."]',
 '["La fermentación larga en frío (24 horas) es la que da sabor y ligereza a la masa; no la acortes.","Estira la masa con las manos, nunca con rodillo, para no expulsar el aire del borde.","Escurre bien la mozzarella antes de ponerla; si suelta agua, la pizza queda cruda por el centro."]'),

('a1b2c3d4-0020-4000-8000-000000000020',
 'Curry de garbanzos y espinacas', 'india', 30, false,
 'https://images.unsplash.com/photo-1565557623262-b51c2513a641?w=800&q=80&crop=entropy',
 2.80, 4, '11111111-1111-1111-1111-111111111111',
 '[{"nombre":"garbanzos cocidos","cantidad":400,"unidad":"g","familia":"legumbres"},{"nombre":"espinacas frescas","cantidad":200,"unidad":"g","familia":"verduras"},{"nombre":"tomates triturados","cantidad":400,"unidad":"g","familia":"verduras"},{"nombre":"cebolla","cantidad":1,"unidad":"ud","familia":"verduras"},{"nombre":"ajo","cantidad":3,"unidad":"dientes","familia":"verduras"},{"nombre":"jengibre fresco","cantidad":20,"unidad":"g","familia":"especias"},{"nombre":"leche de coco","cantidad":200,"unidad":"ml","familia":"lacteos"},{"nombre":"curry en polvo","cantidad":2,"unidad":"cda","familia":"especias"},{"nombre":"garam masala","cantidad":1,"unidad":"cdta","familia":"especias"},{"nombre":"aceite de girasol","cantidad":30,"unidad":"ml","familia":"aceites"}]',
 '["Pica la cebolla fina y sofríela en el aceite a fuego medio unos 8 minutos, hasta que esté dorada.","Añade el ajo y el jengibre rallados y cocínalos 2 minutos, removiendo para que no se quemen.","Incorpora el curry en polvo y el garam masala y tuéstalos 1 minuto sin dejar de remover, hasta que suelten su aroma.","Añade el tomate triturado y cocina 5 minutos a fuego medio, hasta que reduzca y oscurezca.","Echa los garbanzos escurridos y la leche de coco. Cuece 10 minutos a fuego suave para que se integren los sabores.","Añade las espinacas frescas y remueve hasta que se marchiten. Prueba, ajusta de sal y sirve con arroz basmati."]',
 '["Tuesta las especias en el aceite unos segundos antes de añadir el tomate para despertar su aroma, pero sin que se quemen o amargarán.","Si usas garbanzos de bote, enjuágalos bien bajo el grifo para quitarles el líquido de conserva.","Añade las espinacas al final; con el calor residual basta para que se marchiten sin perder su color."]');
